class Solution {
    public int minMinutes(String s, int k) {
        int n = s.length();
        int[] left_counts = new int[3], right_counts = new int[3];
        for (char c : s.toCharArray()) right_counts[c - 'a']++;

        int ans = n, total = 0;
        while (true) {
            int l = 0, r = n - 1;
            while (l < r && left_counts[s.charAt(l) - 'a'] < k && 
                          right_counts[s.charAt(r) - 'a'] < k) {
                int need_left = Math.max(0, k - left_counts[s.charAt(l) - 'a']);
                int need_right = Math.max(0, k - right_counts[s.charAt(r) - 'a']);
                if (need_left <= need_right) {
                    total += need_left;
                    l++;
                    left_counts[s.charAt(l) - 'a']++;
                    right_counts[s.charAt(l) - 'a']--;
                } else {
                    total += need_right;
                    r--;
                    right_counts[s.charAt(r) - 'a']--;
                    left_counts[s.charAt(r) - 'a']++;
                }
            }
            ans = Math.min(ans, total);
            if (l + 1 < s.length()) {
                total -= left_counts[s.charAt(l) - 'a'];
                left_counts[s.charAt(l) - 'a']--;
                right_counts[s.charAt(l + 1) - 'a']++;
                l++;
            } else break;
        }
        if(left_counts[0] >= k && left_counts[1] >= k && left_counts[2] >= k) return ans;
        return -1;
    }
}
```

